"from flask import Flask\nfrom flask_sqlalchemy import SQLAlchemy\nfrom config import Config\n\ndb = SQLAlchemy()\n\ndef create_app(config_class=Config):\n    app = Flask(__name__)\n    app.config.from_object(config_class)\n\n    db.init_app(app)\n\n    from app.routes import bp as main_bp\n    app.register_blueprint(main_bp)\n\n    # Database creation & Seeding\n    with app.app_context():\n        db.create_all()\n        \n        # Seed targets (Zadanie 3 color parameters)\n        from app.models import Mission\n        if not Mission.query.first():\n            default_colors = [\n                Mission(name=\"Red Target Search\", description=\"Detects and aligns to the bright red target cylinder, stops at a safe distance, and logs coordinates.\", target_color=\"red\"),\n                Mission(name=\"Green Target Search\", description=\"Detects and approaches the green target card placed in the search field.\", target_color=\"green\"),\n                Mission(name=\"Blue Target Search\", description=\"Enforces search rotation until the high-contrast blue target is centered.\", target_color=\"blue\"),\n                Mission(name=\"Yellow Target Search\", description=\"Scans room environment for yellow marker identifiers.\", target_color=\"yellow\")\n            ]\n            for c in default_colors:\n                db.session.add(c)\n            db.session.commit()\n\n    return app\n"